}

#include <torch/extension.h>
#include <cuda_runtime.h>
#include <math.h>

#define HEAD_DIM 72
#define HEAD_DIM_QUARTER 18

// ---------------------------------------------------------------------------
// Algebraic collapse of the reference's scatter+matmul into a per-patch
// weighted reduction.  The reference does:
//
//   grad_emb  = -grad_cos * sin(emb) + grad_sin * cos(emb)          [P,72]
//   grad_rpe  = grad_emb[:,:36] + grad_emb[:,36:]                   [P,36]
//   grad_idx  = grad_rpe.reshape(P,2,18)                            [P,2,18]
//   grad_freqs[pos[:,0]] += grad_idx[:,0,:]    (scatter index_add)
//   grad_freqs[pos[:,1]] += grad_idx[:,1,:]
//   grad_inv  = arange(G) @ grad_freqs                              [18]
//
// Substituting seq[g]=g collapses the scatter+matmul to:
//
//   out[j] = sum_p h_p * (gs·cos(e)-gc·sin(e))[p,j]
//          + sum_p w_p * (gs·cos(e)-gc·sin(e))[p,j+18]
//          + sum_p h_p * (gs·cos(e)-gc·sin(e))[p,j+36]
//          + sum_p w_p * (gs·cos(e)-gc·sin(e))[p,j+54]
//
//   where h = pos_ids[p,0],  w = pos_ids[p,1]
//
// 2D thread block (c, p) = (column, local_patch) gives coalesced loads:
//   threads with consecutive c access consecutive memory addresses.
//   Block-level reduction via shared-memory atomics, then 18 global atomics.
// ---------------------------------------------------------------------------

__global__ void vrope_bwd_kernel(
    const float* __restrict__ grad_cos,
    const float* __restrict__ grad_sin,
    const int64_t* __restrict__ pos_ids,
    const float* __restrict__ emb,
    float* __restrict__ output,
    int P)
{
    // 2D block: (HEAD_DIM, BLOCK_P)
    // thread (c, p) loads column c of patch (block_start + p)
    int c = threadIdx.x;          // column [0, HEAD_DIM)
    int local_p = threadIdx.y;    // patch within block [0, BLOCK_P)
    int global_p = blockIdx.x * blockDim.y + local_p;

    __shared__ float smem[HEAD_DIM_QUARTER];

    // Initialize shared-memory partials to zero
    if (c < HEAD_DIM_QUARTER && local_p == 0) {
        smem[c] = 0.0f;
    }
    __syncthreads();

    float partial = 0.0f;

    if (global_p < P) {
        // Coalesced load: threads with consecutive c read consecutive addresses
        int base = global_p * HEAD_DIM + c;
        float gc = grad_cos[base];
        float gs = grad_sin[base];
        float e   = emb[base];

        // Accurate sin/cos (libm, ~0.5 ULP) — matches reference's emb.sin()/emb.cos()
        float sin_e = sinf(e);
        float cos_e = cosf(e);
        float ge = gs * cos_e - gc * sin_e;

        // Weight: h_f for even column-groups (0, 2), w_f for odd (1, 3)
        int col_group = c / HEAD_DIM_QUARTER;  // 0, 1, 2, or 3
        float weight;
        if (col_group == 0 || col_group == 2) {
            weight = (float)pos_ids[global_p * 2];      // height index
        } else {
            weight = (float)pos_ids[global_p * 2 + 1];  // width index
        }
        partial = weight * ge;
    }

    // Block-level reduction: atomically add to shared memory
    int out_idx = c % HEAD_DIM_QUARTER;
    atomicAdd(&smem[out_idx], partial);

    __syncthreads();

    // Single thread writes the block's 18 partials to global memory
    if (c == 0 && local_p == 0) {
        for (int j = 0; j < HEAD_DIM_QUARTER; j++) {
            atomicAdd(&output[j], smem[j]);
        }
    }
}


torch::Tensor run(
    torch::Tensor grad_cos,
    torch::Tensor grad_sin,
    torch::Tensor pos_ids,
    torch::Tensor inv_freq,
    torch::Tensor emb)
{
    int P = grad_cos.size(0);

    // Zero-initialized: the kernel uses atomicAdd to accumulate
    auto output = torch::zeros({HEAD_DIM_QUARTER}, grad_cos.options());

    // Per-shape BLOCK_P tuning:
    //   P <= 256: BLOCK_P=2 → 144 threads/block, fewer global atomics
    //   P >  256: BLOCK_P=4 → 288 threads/block, better occupancy
    int BLOCK_P = (P <= 256) ? 2 : 4;
    dim3 block(HEAD_DIM, BLOCK_P);
    dim3 grid((P + BLOCK_P - 1) / BLOCK_P);

    vrope_bwd_kernel<<<grid, block>>>(
        grad_cos.data_ptr<float>(),
        grad_sin.data_ptr<float>(),
        pos_ids.data_ptr<int64_t>(),
        emb.data_ptr<float>(),
        output.data_ptr<float>(),
        P);

    return output;
}


